"use strict";parserFactory.register("mangaread.co",()=>new MangaReadParser);class MangaReadParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("li.wp-manga-chapter a")].map(e=>util.hyperLinkToChapter(e)).reverse()}findContent(e){return Parser.findConstrutedContent(e)}extractTitleImpl(e){return e.querySelector("div.post-title h1")}extractAuthor(e){let t=e.querySelector("div.author-content a");return null===t?super.extractAuthor(e):t.textContent}findChapterTitle(e){return e.querySelector("h1")}async fetchChapter(e){let t=(await HttpClient.wrapFetch(e)).responseXML,r=Parser.makeEmptyDocForContent(e);r.dom.base=e;let a=this.makeImgUrls(t);return this.buildPageWithImageTags(a,r)}makeImgUrls(e){let t=e.querySelector(".wp-manga-chapter-img"),r=[...e.querySelector("select#single-pager").querySelectorAll("option")],a=t.getAttribute("data-lazy-src"),n=a.lastIndexOf("/");a=a.substring(0,n+1);let l=[];for(let e=1;e<=r.length;++e){let t="00"+e;t=t.substring(t.length-3),l.push(a+t+".jpg")}return l}async buildPageWithImageTags(e,t){for(let r of e){let e=t.dom.createElement("img");e.src=r,t.content.appendChild(e)}return t.dom}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.summary_image")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.summary__content")]}}